INSERT INTO TBL_TENANT_CONFIG (TENANT_ID, PROPERTY_NAME, CONFIG_NAME, PROPERTY_VALUE, DESCRIPTION, REGDATE, CONFIG_TYPE) VALUES (0, 'PrimaryTimeZone', '시스템 표준 시간대', '235|+09:00', '시스템 primary 표준 시간대를 설정한다.시스템 Primary 표준 시간대 설정  (첫 로그인 시 사용자의 표준 시간대를 정할 수 없을 경우 시스템의 표준 시간대를 따름) (default: 235|+09:00)', '2017-01-06 00:00:00', '일반');
INSERT INTO TBL_TENANT_CONFIG (TENANT_ID, PROPERTY_NAME, CONFIG_NAME, PROPERTY_VALUE, DESCRIPTION, REGDATE, CONFIG_TYPE) VALUES (0, 'cloudAddUserMailSubject', '클라우드 유저 추가 알림 메일 제목', '[알림] 클라우드 서버에 새로운 유저가 추가되었습니다', '클라우드 서버에서 유저가 추가되면 보내는 알림 메일의 제목', '2017-01-06 00:00:00', '일반');
INSERT INTO TBL_TENANT_CONFIG (TENANT_ID, PROPERTY_NAME, CONFIG_NAME, PROPERTY_VALUE, DESCRIPTION, REGDATE, CONFIG_TYPE) VALUES (0, 'cloudAddUserMailContent', '클라우드 유저 추가 알림 메일 내용', '<html><head><meta charset=\"utf-8\"></head><body><div style=\"width: 80%;margin: 0px auto;\"><p style=\"font-weight: bold;\">클라우드에 유저가 추가되었습니다. 해당 내용은 아래와 같습니다.</p><ul><ol>서버 메일 주소: %s</ol><ol>추가한 관리자명: %s</ol><ol>추가된 유저명: %s</ol><ol>일자: %s</ol></ul><div id=\"cloud-message\" style=\"margin: 0px auto;margin-top: 20px;padding: 10px;background: rgb(238, 238, 238);height: 100px;\"><h3 style=\"margin: 0px;\">* 추가된 유저 요금은 일할계산되어 자동 익월 청구됩니다.<br>* 문의: 고객지원센터 080-258-0007</h3></div></div></body></html>', '클라우드 서버에서 유저가 추가되면 보내는 알림 메일의 내용 (HTML)', '2017-01-06 00:00:00', '일반');
INSERT INTO TBL_TENANT_CONFIG (TENANT_ID, PROPERTY_NAME, CONFIG_NAME, PROPERTY_VALUE, DESCRIPTION, REGDATE, CONFIG_TYPE) VALUES (0, 'cloudAddUserMailTo', '클라우드 유저 추가 알림 메일 받는 사람', '', '클라우드 서버에서 유저가 추가되면 보내는 알림 메일을 받는 사람 (, 로 구분하여 여러명을 나타낸다)', '2017-01-06 00:00:00', '일반');
